<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="90" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Let's Talk Tangible Assets</p>
      <p slot="message">
        Gather your assets and/or liabilities that you put up against your mortgage.
      </p>
    </message-modal>
    <div class="container">
      <div class="box">

        <div class="columns is-centered">
          <div class="column is-two-thirds-desktop">
            <b-field label="Primary banking" :addons="false" class="info">
              <b-tooltip label="Please provide us with your main bank account details." position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-field>
                <b-input v-model="bankingInstitution" type="text" icon="piggy-bank" style="flex: 3;" placeholder="Instutution" expanded></b-input>
                <b-input v-model="accountBalance" icon="dollar-sign" style="flex: 2;" placeholder="Balance"></b-input>
                <b-select v-model="primaryAccount" placeholder="Account">
                  <option value="chequing">Chequing</option>
                  <option value="saving">Saving</option>
                </b-select>
              </b-field>
            </b-field>
          </div>
        </div>

        <assets-liabilities></assets-liabilities>

        <div class="columns is-centered">
          <div class="column is-one-third-tablet is-one-quarter-widescreen">
            <b-field label="Do you own real estate?" :addons="false" class="info">
              <b-tooltip label="Commercial and/or residential" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <div class="input is-borderless is-shadowless">
                <b-radio v-model="ownsRealEstate" native-value="true">
                  Yes
                </b-radio>
                <b-radio v-model="ownsRealEstate" native-value="false">
                  No
                </b-radio>
              </div>
            </b-field>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <hr>
          </div>
          </div>

          <to-page back="/employment" :next="toProperties" text="Go to Properties Form"></to-page>

        </div>
      </div>
    </div>
</template>

<script>
import assetsLiabilities from "../components/assets-liabilities.vue";
export default {
  data() {
    return {
      page: "Page 6",
      heading: "Your Assets & Liabilities",
      toggled: false,
      assetsPage: {
        ownsRealEstate: "No"
      }
    };
  },
  computed: {
    toProperties() {
      return this.ownsRealEstate ? "/properties" : "/signatures";
    },
    toPropertiesText() {
      return this.ownsRealEstate ? "Go to Properties Page" : "Sign the Form";
    },
    bankingInstitution: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.bankingInstitution;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.bankingInstitution = val;
      }
    },
    accountBalance: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.accountBalance;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.accountBalance = val;
      }
    },
    primaryAccount: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.primaryAccount;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.primaryAccount = val;
      }
    },
    ownsRealEstate: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.ownsRealEstate;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.ownsRealEstate = val;
      }
    }
  },
  components: {
    assetsLiabilities
  }
};
</script>