            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="netIncome" expanded icon="dollar-sign" placeholder="CAD / year"></b-input>
        </b-field>
      </div>
      <div class="column is-one-third">
        <b-field label="Gross income" :addons="false" class="info">
          <b-tooltip label="How much does your business earn annually?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="grossIncome" expanded icon="dollar-sign" placeholder="CAD / year"></b-input>
        </b-field>
      </div>
    </div>

    <div key="random_77240vvg" class="columns is-centered">
      <div class="column is-one-third">
        <b-field label="Occupation" :addons="false" class="info">
          <b-tooltip label="What is your role at your company?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="occupation" expanded icon="user-tie" placeholder="I'm a"></b-input>
        </b-field>
      </div>
      <div class="column is-one-third">
        <b-field label="Industry" :addons="false" class="info">
          <b-tooltip label="What industry fits your business best?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="industry" expanded icon="industry" placeholder="I'm in"></b-input>
        </b-field>
      </div>
    </div>

    <div key="random_z34f" class="columns is-centered">
      <div class="column is-one-third">
        <b-field label="Time on the job" :addons="false" class="info">
          <b-tooltip label="How long have you owned this business?" position="is-left" size="is-medium" type="is-dark" animated multilined>
