          </b-tooltip>
          <b-input v-model="timeAtJob" expanded icon="briefcase" placeholder="Years"></b-input>
        </b-field>
      </div>
      <div class="column is-one-third">
        <b-field label="Time in the industry" :addons="false" class="info">
          <b-tooltip label="How long has your company operated in the current industry?" position="is-left" size="is-medium" type="is-dark" animated multilined>
            <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
          </b-tooltip>
          <b-input v-model="timeInIndustry" expanded icon="industry" placeholder="Years"></b-input>
        </b-field>
      </div>
    </div>

  </section>
</template>

<script>
import addressBlock from "../components/address-block.vue";

export default {
  components: {
    addressBlock
  },
  methods: {
    employmentRoute(e) {
      JSON.parse(e);
      if (this.$store.state.EmploymentForm.selfEmployed) {
        router.replace({ path: "/employment/self" });
      } else {
        router.replace({ path: "/employment/company" });
      }
    }
  },
  computed: {
    netIncome: {
      get() {
        return this.$store.state.EmploymentForm.netIncome;
      },
      set(val) {
        this.$store.state.EmploymentForm.netIncome = val;
      }
    },
    industry: {
      get() {
        return this.$store.state.EmploymentForm.industry;
      },
      set(val) {
        this.$store.state.EmploymentForm.industry = val;
      }
    },
    grossIncome: {
      get() {
        return this.$store.state.EmploymentForm.grossIncome;
      },
      set(val) {
        this.$store.state.EmploymentForm.grossIncome = val;
      }
    },
    timeInIndustry: {
      get() {
        return this.$store.state.EmploymentForm.timeInIndustry;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeInIndustry = val;
      }
    },
    timeAtJob: {
      get() {
        return this.$store.state.EmploymentForm.timeAtJob;
      },
      set(val) {
        this.$store.state.EmploymentForm.timeAtJob = val;
      }
    },
    registrationDate: {
      get() {
        return this.$store.state.EmploymentForm.registrationDate;
      },
      set(val) {
        this.$store.state.EmploymentForm.registrationDate = val;
      }
    },
    companyName: {
      get() {
        return this.$store.state.EmploymentForm.companyName;
      },
      set(val) {
        this.$store.state.EmploymentForm.companyName = val;
      }
    },
    occupation: {
      get() {
        return this.$store.state.EmploymentForm.occupation;
      },
      set(val) {
        this.$store.state.EmploymentForm.occupation = val;
      }
    },
    businessName: {
      get() {
        return this.$store.state.EmploymentForm.businessName;
      },
      set(val) {
        this.$store.state.EmploymentForm.businessName = val;
      }
    },
    businessType: {
      get() {
        return this.$store.state.EmploymentForm.businessType;
      },
      set(val) {
        this.$store.state.EmploymentForm.businessType = val;
      }
    }
  }
};
</script>