<template>
  <div class="columns is-centered">
    <div class="column is-two-thirds-desktop">
      <hr>
      <p class="has-text-weight-bold has-text-grey-light is-size-5">
        <i class="fas fa-map-marked-alt"></i>
        {{message}}
      </p>
      <div class="columns">
        <div class="column">
          <b-field label="Street and unit">
            <b-input :icon="icon" v-model="main"></b-input>
          </b-field>
        </div>
      </div>
      <div class="columns">
        <div class="column is-one-third">
          <b-field label="City">
            <b-input :icon="icon" v-model="city"></b-input>
          </b-field>
        </div>
        <div class="column is-one-third">
          <b-field label="Province">
            <b-input :icon="icon" value="Ontario" v-model="province">Ontario</b-input>
          </b-field>
        </div>
        <div class="column is-one-third">
          <b-field label="Postal code">
            <b-input :icon="icon" v-model="postal"></b-input>
          </b-field>
        </div>
      </div>
      <hr>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    form: Object,
    icon: String,
    message: String
  },
  computed: {
    main: {
      get() {
        return this.form.main;
      },
      set(val) {
        this.form.main = val;
      }
    },
    city: {
      get() {
        return this.form.city;
      },
      set(val) {
        this.form.city = val;
      }
    },
    province: {
      get() {
        return this.form.province;
      },
      set(val) {
        this.form.province = val;
      }
    },
    postal: {
      get() {
        return this.form.postal;
      },
      set(val) {
        this.form.postal = val;
      }
    }
  }
}
</script>
